<section class="portal-page"><div class="portal-head"><div><span class="eyebrow">PATIENT PORTAL</span><h1>My Appointments</h1><p>Review upcoming and previous appointment records.</p></div><a class="btn" href="<?=url('book-appointment')?>">Book New Appointment</a></div><div class="status-tabs"><?php foreach([''=>'All','pending'=>'Pending','confirmed'=>'Confirmed','completed'=>'Completed','cancelled'=>'Cancelled']as$k=>$v):?><a class="<?=$status===$k?'active':''?>" href="<?=url('appointments'.($k?'?status='.$k:''))?>"><?=$v?></a><?php endforeach;?></div><div class="appointment-list detailed"><?php foreach($appointments as$a):?><a href="<?=url('appointment?id='.$a['id'])?>"><div><span><?=e($a['appointment_number'])?></span><h3><?=e($a['doctor_name'])?></h3><small><?=e($a['department_name'])?> • <?=date('d M Y',strtotime($a['appointment_date']))?> • <?=date('h:i A',strtotime($a['appointment_time']))?></small></div><span class="status-pill <?=e($a['status'])?>"><?=e(ucfirst($a['status']))?></span></a><?php endforeach;?><?php if(!$appointments):?><div class="empty">No appointments found in this category.</div><?php endif;?></div></section>

